<!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Soft Soluções | Sistemas Sob Medida</title>
    <link rel="stylesheet" href="style.css">
</head>
<body>

<header>
    <div class="container">
        <h1>🚀 Soft Soluções</h1>
        <nav>
            <a href="#servicos">Serviços</a>
            <a href="#orcamento">Orçamento</a>
            <a href="#contato">Contato</a>
        </nav>
    </div>
</header>

<section class="hero">
    <div class="container">
        <h2>Sistemas personalizados para o seu negócio</h2>
        <p>
            Desenvolvemos sistemas para clínicas, empresas,
            controle de estoque, painéis de senhas e soluções sob medida.
        </p>

        <a href="#orcamento" class="btn">
            Solicitar Orçamento
        </a>
    </div>
</section>

<section id="servicos">
    <div class="container">
        <h2>Nossos Serviços</h2>

        <div class="cards">

            <div class="card">
                💻
                <h3>Sistemas Web</h3>
            </div>

            <div class="card">
                📱
                <h3>Aplicativos</h3>
            </div>

            <div class="card">
                🏥
                <h3>Sistemas para Clínicas</h3>
            </div>

            <div class="card">
                🎫
                <h3>Painel de Senhas</h3>
            </div>

            <div class="card">
                📊
                <h3>Dashboards</h3>
            </div>

            <div class="card">
                ⚙️
                <h3>Automação</h3>
            </div>

        </div>
    </div>
</section>

<section id="orcamento">
    <div class="container">
        <h2>Solicite um Orçamento</h2>

        <form id="formulario">

            <input type="text" id="nome" placeholder="Nome" required>

            <input type="text" id="empresa" placeholder="Empresa">

            <input type="text" id="telefone" placeholder="WhatsApp">

            <textarea
                id="descricao"
                placeholder="Descreva sua necessidade"
                rows="6"
                required></textarea>

            <button type="submit">
                Enviar Solicitação
            </button>

        </form>
    </div>
</section>

<footer id="contato">
    <h3>Soft Soluções</h3>
    <p>📍 Macapá - AP</p>
    <p>📞 (96) 99195-1440</p>
</footer>

<script src="script.js"></script>
</body>
</html>
```
