*{
    margin:0;
    padding:0;
    box-sizing:border-box;
}

body{
    font-family:Arial,sans-serif;
    background:#0f172a;
    color:white;
}

.container{
    width:90%;
    max-width:1200px;
    margin:auto;
}

header{
    padding:20px 0;
}

header .container{
    display:flex;
    justify-content:space-between;
    align-items:center;
}

nav a{
    color:white;
    margin-left:20px;
    text-decoration:none;
}

.hero{
    text-align:center;
    padding:100px 20px;
}

.hero h2{
    font-size:3rem;
    margin-bottom:20px;
}

.hero p{
    max-width:700px;
    margin:auto;
}

.btn{
    display:inline-block;
    margin-top:30px;
    background:#2563eb;
    color:white;
    padding:15px 30px;
    border-radius:10px;
    text-decoration:none;
}

#servicos{
    padding:80px 0;
}

.cards{
    display:grid;
    grid-template-columns:repeat(auto-fit,minmax(250px,1fr));
    gap:20px;
    margin-top:40px;
}

.card{
    background:#1e293b;
    padding:30px;
    border-radius:15px;
    text-align:center;
    font-size:2rem;
}

#orcamento{
    padding:80px 0;
}

form{
    display:flex;
    flex-direction:column;
    gap:15px;
    max-width:700px;
    margin:auto;
}

input,
textarea{
    padding:15px;
    border:none;
    border-radius:10px;
}

button{
    padding:15px;
    background:#2563eb;
    color:white;
    border:none;
    border-radius:10px;
    cursor:pointer;
}

footer{
    text-align:center;
    padding:40px;
}
