            <input 
                type="text" 
                id="taskInput" 
                placeholder="Adicione uma nova tarefa..."
                class="task-input"
            >
            <button id="addBtn" class="btn-add">Adicionar</button>
        </div>

        <div class="filter-section">
            <button class="filter-btn active" data-filter="all">Todas (0)</button>
            <button class="filter-btn" data-filter="active">Ativas (0)</button>
            <button class="filter-btn" data-filter="completed">Concluídas (0)</button>
        </div>

        <ul id="taskList" class="task-list">
            <!-- Tasks will be added here -->
        </ul>

        <div class="empty-state" id="emptyState">
            <p>🎉 Nenhuma tarefa! Adicione uma para começar.</p>
        </div>

        <div class="actions">
            <button id="clearCompleted" class="btn-secondary">Limpar Concluídas</button>
            <button id="clearAll" class="btn-danger">Limpar Tudo</button>
        </div>
    </div>
</div>

<script src="script.js"></script>
</body>
</html>"},{"path":"todo/style.css","content":"* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    padding: 20px;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    width: 100%;
    max-width: 600px;
}

.todo-app {
    background: white;
    border-radius: 15px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    padding: 30px;
    animation: slideUp 0.3s ease-out;
}

@keyframes slideUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

header {
    text-align: center;
    margin-bottom: 30px;
}

header h1 {
    color: #333;
    font-size: 2.5rem;
    margin-bottom: 8px;
}

header p {
    color: #999;
    font-size: 0.95rem;
}

.input-section {
    display: flex;
    gap: 10px;
    margin-bottom: 25px;
}

.task-input {
    flex: 1;
    padding: 15px;
    border: 2px solid #e0e0e0;
    border-radius: 10px;
    font-size: 1rem;
    transition: border-color 0.3s ease;
}

.task-input:focus {
    outline: none;
    border-color: #667eea;
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
}

.btn-add {
    padding: 15px 30px;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    border: none;
    border-radius: 10px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.btn-add:hover {
    transform: translateY(-2px);
    box-shadow: 0 10px 20px rgba(102, 126, 234, 0.3);
}

.btn-add:active {
    transform: translateY(0);
}

.filter-section {
    display: flex;
    gap: 10px;
    margin-bottom: 20px;
    justify-content: center;
    flex-wrap: wrap;
}

.filter-btn {
    padding: 10px 20px;
    background: #f5f5f5;
    border: 2px solid transparent;
    border-radius: 8px;
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
    color: #666;
    transition: all 0.3s ease;
}

.filter-btn:hover {
    background: #efefef;
}

.filter-btn.active {
    background: #667eea;
    color: white;
    border-color: #667eea;
}

.task-list {
    list-style: none;
    margin-bottom: 20px;
    max-height: 400px;
    overflow-y: auto;
}

.task-item {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 15px;
    background: #f9f9f9;
    border-radius: 10px;
    margin-bottom: 10px;
    animation: slideIn 0.3s ease-out;
    transition: all 0.3s ease;
}

@keyframes slideIn {
    from {
        opacity: 0;
        transform: translateX(-10px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

.task-item:hover {
    background: #f0f0f0;
    transform: translateX(5px);
}

.task-item.completed {
    opacity: 0.6;
}

.task-item.completed .task-text {
    text-decoration: line-through;
    color: #999;
}

.checkbox {
    width: 24px;
    height: 24px;
    cursor: pointer;
    accent-color: #667eea;
}

.task-text {
    flex: 1;
    color: #333;
    word-break: break-word;
}

.task-date {
    font-size: 0.8rem;
    color: #999;
    white-space: nowrap;
}

.btn-delete {
    background: #ff4757;
    color: white;
    border: none;
    border-radius: 8px;
    padding: 8px 12px;
    cursor: pointer;
    font-size: 0.85rem;
    font-weight: 600;
    transition: all 0.3s ease;
}

.btn-delete:hover {
    background: #ff3838;
    transform: scale(1.05);
}

