{"branch": "main", "files": [{"content":"<!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Gerador de Piadas | Soft Soluções</title>
    <link rel="stylesheet" href="style.css">
</head>
<body>

<div class="container">
    <div class="joke-app">
        <header>
            <h1>😂 Gerador de Piadas</h1>
            <p>Clique no botão para ouvir uma piada engraçada!</p>
        </header>

        <div class="joke-display">
            <div class="joke-content" id="jokeContent">
                <p class="loading">Carregando piada...</p>
            </div>
        </div>

        <div class="controls">
            <button id="newJokeBtn" class="btn-primary">Nova Piada 🎲</button>
            <button id="readJokeBtn" class="btn-secondary" disabled>Ouvir 🔊</button>
            <button id="copyJokeBtn" class="btn-secondary" disabled>Copiar 📋</button>
        </div>

        <div class="settings">
            <label for="jokeType">Tipo de Piada:</label>
            <select id="jokeType">
                <option value="general">Geral</option>
                <option value="programming">Programação</option>
                <option value="knock-knock">Toc-Toc</option>
            </select>
        </div>

        <div class="stats">
            <p>Piadas geradas: <span id="jokeCount">0</span></p>
        </div>
    </div>
</div>

<script src="script.js"></script>
</body>
</html>","path":"jokes/index.html"},{"content":"* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
    min-height: 100vh;
    padding: 20px;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    width: 100%;
    max-width: 700px;
}

.joke-app {
    background: white;
    border-radius: 20px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    padding: 40px;
    animation: slideUp 0.3s ease-out;
}

@keyframes slideUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes bounce {
    0%, 100% {
        transform: translateY(0);
    }
    50% {
        transform: translateY(-10px);
    }
}

header {
    text-align: center;
    margin-bottom: 40px;
}

header h1 {
    color: #333;
    font-size: 2.5rem;
    margin-bottom: 10px;
    animation: bounce 2s infinite;
}

header p {
    color: #666;
    font-size: 1rem;
}

.joke-display {
    background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
    border-radius: 15px;
    padding: 30px;
    margin-bottom: 30px;
    min-height: 150px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.joke-content {
    color: white;
    text-align: center;
    font-size: 1.2rem;
    line-height: 1.6;
    word-wrap: break-word;
}

.joke-content p {
    margin: 10px 0;
}

.joke-setup {
    font-weight: 600;
    font-size: 1.1rem;
    margin-bottom: 15px;
}

.joke-punchline {
    font-style: italic;
    font-size: 1rem;
    margin-top: 15px;
    padding-top: 15px;
    border-top: 2px solid rgba(255, 255, 255, 0.3);
}

.loading {
    font-size: 1.1rem;
    color: white;
    animation: pulse 1.5s infinite;
}

@keyframes pulse {
    0%, 100% {
        opacity: 1;
    }
    50% {
        opacity: 0.5;
    }
}

.controls {
    display: flex;
    gap: 10px;
    margin-bottom: 25px;
    flex-wrap: wrap;
    justify-content: center;
}

.btn-primary,
.btn-secondary {
    padding: 12px 24px;
    border: none;
    border-radius: 10px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
}

.btn-primary {
    background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
    color: white;
    flex: 1;
    min-width: 150px;
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 10px 20px rgba(245, 87, 108, 0.3);
}

.btn-primary:active {
    transform: translateY(0);
}

.btn-primary:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none;
}

.btn-secondary {
    background: #f0f0f0;
    color: #333;
    flex: 1;
    min-width: 120px;
}

.btn-secondary:hover:not(:disabled) {
    background: #e0e0e0;
    transform: translateY(-2px);
}

.btn-secondary:disabled {
