class JokeGenerator {
    constructor() {
        this.currentJoke = null;
        this.jokeCount = 0;
        this.jokeType = 'general';
        this.apiUrl = 'https://official-joke-api.appspot.com';
        this.init();
    }

    init() {
        this.setupEventListeners();
        this.loadJokeCount();
        this.getRandomJoke();
    }

    setupEventListeners() {
        document.getElementById('newJokeBtn').addEventListener('click', () => this.getRandomJoke());
        document.getElementById('readJokeBtn').addEventListener('click', () => this.readJokeAloud());
        document.getElementById('copyJokeBtn').addEventListener('click', () => this.copyJoke());
        document.getElementById('jokeType').addEventListener('change', (e) => {
            this.jokeType = e.target.value;
            this.getRandomJoke();
        });
    }

    async getRandomJoke() {
        const btn = document.getElementById('newJokeBtn');
        const readBtn = document.getElementById('readJokeBtn');
        const copyBtn = document.getElementById('copyJokeBtn');
        const jokeContent = document.getElementById('jokeContent');

        // Disable buttons and show loading
        btn.disabled = true;
        readBtn.disabled = true;
        copyBtn.disabled = true;
        jokeContent.innerHTML = '<p class="loading">Carregando piada engraçada... 😄</p>';

        try {
            let url = `${this.apiUrl}/random_joke`;

            // Ajustar URL baseado no tipo selecionado
            if (this.jokeType === 'programming') {
                url = `${this.apiUrl}/jokes/programming/random`;
            } else if (this.jokeType === 'knock-knock') {
                url = `${this.apiUrl}/jokes/knock-knock/random`;
            }

            const response = await fetch(url);

            if (!response.ok) {
                throw new Error(`Erro: ${response.status}`);
            }

            const data = await response.json();
            this.currentJoke = data;
            this.displayJoke(data);
            this.incrementJokeCount();

        } catch (error) {
            console.error('Erro ao buscar piada:', error);
            jokeContent.innerHTML = `
                <div class="error">
                    <p>❌ Erro ao carregar a piada!</p>
                    <p>${error.message}</p>
                </div>
            `;
        } finally {
            // Re-enable buttons
            btn.disabled = false;
            readBtn.disabled = false;
            copyBtn.disabled = false;
        }
    }

    displayJoke(joke) {
        const jokeContent = document.getElementById('jokeContent');

        if (joke.setup && joke.delivery) {
            // Knock-knock ou joke com setup/delivery
            jokeContent.innerHTML = `
                <div class="joke-item">
                    <p class="joke-setup">${this.escapeHtml(joke.setup)}</p>
                    <p class="joke-punchline">→ ${this.escapeHtml(joke.delivery)}</p>
                </div>
            `;
        } else {
            // Piada simples
            jokeContent.innerHTML = `
                <div class="joke-item">
                    <p class="joke-setup">${this.escapeHtml(joke.joke)}</p>
                </div>
            `;
        }
    }

    readJokeAloud() {
        if (!this.currentJoke) return;

        const text = this.getJokeText();
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'pt-BR';
        utterance.rate = 1;
        utterance.pitch = 1;
        utterance.volume = 1;

        window.speechSynthesis.cancel(); // Cancelar fala anterior
        window.speechSynthesis.speak(utterance);
    }

    copyJoke() {
        const text = this.getJokeText();
        navigator.clipboard.writeText(text).then(() => {
            const copyBtn = document.getElementById('copyJokeBtn');
            const originalText = copyBtn.textContent;
            copyBtn.textContent = 'Copiado! ✅';
            setTimeout(() => {
                copyBtn.textContent = originalText;
            }, 2000);
        }).catch(err => {
            console.error('Erro ao copiar:', err);
            alert('Erro ao copiar a piada!');
        });
    }

    getJokeText() {
        if (this.currentJoke.setup && this.currentJoke.delivery) {
            return `${this.currentJoke.setup}\n${this.currentJoke.delivery}`;
        } else {
            return this.currentJoke.joke;
        }
    }

    incrementJokeCount() {
        this.jokeCount++;
        localStorage.setItem('jokeCount', this.jokeCount);
        document.getElementById('jokeCount').textContent = this.jokeCount;
    }

    loadJokeCount() {
        const saved = localStorage.getItem('jokeCount');
        this.jokeCount = saved ? parseInt(saved) : 0;
        document.getElementById('jokeCount').textContent = this.jokeCount;
    }

    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
}

// Initialize the app
document.addEventListener('DOMContentLoaded', () => {
    new JokeGenerator();
});
